// {
// #ifdef ENA_VEC_ISA
#ifdef ENA_DYNAMIC_CALC_CACHE_CONFIG
    unsigned int cache_size_byte = 0, tiling_size = 1;
    vec_calc_tiling_size_and_cache_config(&cache_size_byte, &tiling_size);
#else
    //cache is 512KB
    const unsigned int cache_size_byte = 512 << 10;
#endif
    unsigned int tiling_row_B;
    //col > 8: assume max way is 8 to prevent /0
    if(col < tiling_size && col > 8)
    {
        tiling_row_B = higher_power_2(col);
    }
    else
    {
        tiling_row_B = tiling_size;
    }
    /*
