            NDS_VEC_VNSRA_WV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V24);  //new_val >> (total_shift - 1);
            NDS_VEC_VSSRA_VI(NDS_VEC_V0, NDS_VEC_V0, 1);            //(result + 1) >> 1;

            // Add offset
            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, out_offset);
            // Clamp the result
            NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, act_min);
            NDS_VEC_VMIN_VX(NDS_VEC_V0, NDS_VEC_V0, act_max);

            // Narrowing result
            NDS_VEC_VSETVLI(vl, vl, DEF_VTYPEVW_SEW, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSETVLI(vl, vl, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
            DEF_VSTORE_V(NDS_VEC_V0, out);

            avl -= vl;
            tmp_out += vl;
            pContri += vl;
            pOut_scale += vl;
            pOut_shift += vl;
            out += vl;
        }
