#else
    int vl, avl;
    const long cst_0 = 0,
               cst_30 = 30,
               cst_32 = 32;
    for(int i = 0; i < row; i++)
    {
        avl = col2;
        const MM_TYPE_VQ *pContri = contri_buf;
        const MM_TYPE_VQ *pOut_scale = out_scale;
        const MM_TYPE_VQ *pOut_shift = out_shift;
        while(avl > 0)
        {
            // Add contribution
            NDS_VEC_VSETVLI(vl, avl, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M4);
            DEF_VLOADVQ_V(NDS_VEC_V0, tmp_out);
            DEF_VLOADVQ_V(NDS_VEC_V8, pContri);
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);

            // Quantize down
            DEF_VLOADVQ_V(NDS_VEC_V24, pOut_shift);
            DEF_VLOADVQ_V(NDS_VEC_V4, pOut_scale);
            NDS_VEC_VRSUB_VX(NDS_VEC_V24, NDS_VEC_V24, cst_30);
            NDS_VEC_VSUB_VX(NDS_VEC_V28, NDS_VEC_V24, cst_32);  // shift - 32
            // --- simulate 64-bit calcualtion (vwmul) with 32-bit instruction ---
            // high part 32-bit of vwmul results
            NDS_VEC_VMULH_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V4);
            // low part 32-bit of vwmul results
            NDS_VEC_VMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V4);

            // --- simulate 64-bit calcualtion (vnsra) with 32-bit instruction ---
            // results for shift >= 32
            NDS_VEC_VSRA_VV(NDS_VEC_V12, NDS_VEC_V8, NDS_VEC_V28);
            NDS_VEC_VRSUB_VX(NDS_VEC_V28, NDS_VEC_V28, cst_0);  // 32 - shift
            // low part 32-bit results for shift < 32
            NDS_VEC_VSRL_VV(NDS_VEC_V16, NDS_VEC_V4, NDS_VEC_V24);
            // high part 32-bit results for shift < 32
            NDS_VEC_VSLL_VV(NDS_VEC_V20, NDS_VEC_V8, NDS_VEC_V28);
            // results for shift < 32
            NDS_VEC_VOR_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V20);
            // vnsra results
            NDS_VEC_VMSLT_VX(NDS_VEC_V0, NDS_VEC_V24, cst_32);
            NDS_VEC_VMERGE_VVM(NDS_VEC_V8, NDS_VEC_V12, NDS_VEC_V16);

            NDS_VEC_VSSRA_VI(NDS_VEC_V8, NDS_VEC_V8, 1);            //(result + 1) >> 1;

            // Add offset
            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, out_offset);
            // Clamp the result
            NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, act_min);
            NDS_VEC_VMIN_VX(NDS_VEC_V8, NDS_VEC_V8, act_max);

            // Narrowing result
            NDS_VEC_VSETVLI(vl, vl, DEF_VTYPEVW_SEW, NDS_VEC_VTYPE_LMUL_M2);
            NDS_VEC_VNSRA_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSETVLI(vl, vl, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNSRA_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
            DEF_VSTORE_V(NDS_VEC_V8, out);

            avl -= vl;
            tmp_out += vl;
            pContri += vl;
            pOut_scale += vl;
            pOut_shift += vl;
            out += vl;
        }
    }
#endif
    return out;

