static inline void vec_mat_mul_rvv_tiling_vq(const MM_TYPE_A* src1, const MM_TYPE_B* src2, MM_TYPE_VQ* dst, uint32_t row, uint32_t col, uint32_t col2, uint32_t tiling_size)
{
    //2*8 by 8*vl
    int row_2 = row >> 1;
    int max_row = row_2 << 1;

    const MM_TYPE_A* A = src1;
    const MM_TYPE_B* B = src2;
    MM_TYPE_VQ* C = dst;
    int r, k, kk, cc, vl;
    int kk_tiling_size, cc_tiling_size, max_kk_tiling_size;
    const MM_TYPE_A * A11, * A21;
    const MM_TYPE_B * B11, * B21, * B31, * B41, * B51, * B61, * B71, * B81;
    MM_TYPE_VQ * C1, * C2;
    for (kk = 0; kk < col; kk += tiling_size)
    {
        kk_tiling_size = ((kk + tiling_size) > col ? col : (kk + tiling_size));
        if ((kk + tiling_size) <= col)
        {
            max_kk_tiling_size = kk_tiling_size - (tiling_size & 7);
        }
        else
        {
            max_kk_tiling_size = col - ((col - kk) & 7);
        }
        for (cc = 0; cc < col2; cc += tiling_size)
        {
            cc_tiling_size = ((cc + tiling_size) > col2 ? col2 : (cc + tiling_size));
            for (r = 0; r < max_row; r += 2)
            {
                int mulLen = cc_tiling_size - cc;
                while (mulLen > 0)
                {
                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
                    NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0); //sum

                    A11 = A + r * col + kk;
                    A21 = A11 + col;
                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
                    B21 = B11 + col2;
                    B31 = B21 + col2;
                    B41 = B31 + col2;
                    B51 = B41 + col2;
                    B61 = B51 + col2;
                    B71 = B61 + col2;
                    B81 = B71 + col2;
                    C1 = C + r * col2 + cc_tiling_size - mulLen;
                    C2 = C1 + col2;

                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
                    for (k = kk; k < max_kk_tiling_size; k += 8)
                    {
                        DEF_VLOAD_V(NDS_VEC_V16, B11);
                        DEF_VLOAD_V(NDS_VEC_V18, B21);
                        DEF_VLOAD_V(NDS_VEC_V20, B31);
                        DEF_VLOAD_V(NDS_VEC_V22, B41);
                        DEF_VLOAD_V(NDS_VEC_V24, B51);
                        DEF_VLOAD_V(NDS_VEC_V26, B61);
                        DEF_VLOAD_V(NDS_VEC_V28, B71);
                        DEF_VLOAD_V(NDS_VEC_V30, B81);
                        MM_TYPE_A tmpa11 = *A11++;
                        MM_TYPE_A tmpa21 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa21, NDS_VEC_V16);

                        MM_TYPE_A tmpa12 = *A11++;
                        MM_TYPE_A tmpa22 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa12, NDS_VEC_V18);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa22, NDS_VEC_V18);

                        MM_TYPE_A tmpa13 = *A11++;
                        MM_TYPE_A tmpa23 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa13, NDS_VEC_V20);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa23, NDS_VEC_V20);

                        MM_TYPE_A tmpa14 = *A11++;
                        MM_TYPE_A tmpa24 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa14, NDS_VEC_V22);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa24, NDS_VEC_V22);

                        MM_TYPE_A tmpa15 = *A11++;
                        MM_TYPE_A tmpa25 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa15, NDS_VEC_V24);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa25, NDS_VEC_V24);

                        MM_TYPE_A tmpa16 = *A11++;
                        MM_TYPE_A tmpa26 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa16, NDS_VEC_V26);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa26, NDS_VEC_V26);

                        MM_TYPE_A tmpa17 = *A11++;
                        MM_TYPE_A tmpa27 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa17, NDS_VEC_V28);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa27, NDS_VEC_V28);

                        MM_TYPE_A tmpa18 = *A11++;
                        MM_TYPE_A tmpa28 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa18, NDS_VEC_V30);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa28, NDS_VEC_V30);

                        B11 += 8 * col2;
                        B21 += 8 * col2;
                        B31 += 8 * col2;
                        B41 += 8 * col2;
                        B51 += 8 * col2;
                        B61 += 8 * col2;
                        B71 += 8 * col2;
                        B81 += 8 * col2;
                    }
                    for (; k < kk_tiling_size; k++)
                    {
                        DEF_VLOAD_V(NDS_VEC_V16, B11);
                        MM_TYPE_A tmpa11 = *A11++;
                        MM_TYPE_A tmpa21 = *A21++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
                        DEF_VMACC_V(NDS_VEC_V8, tmpa21, NDS_VEC_V16);

                        B11 += col2;
                    }
                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
                    DEF_VLOADVQ_V(NDS_VEC_V16, C1);
                    DEF_VLOADVQ_V(NDS_VEC_V24, C2);

                    NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16);
                    NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V24);

                    DEF_VSTOREVQ_V(NDS_VEC_V0, C1);
                    DEF_VSTOREVQ_V(NDS_VEC_V8, C2);
                    mulLen -= vl;
                }
            }
            for (; r < row; r++)
            {
                int mulLen = cc_tiling_size - cc;
                while (mulLen > 0)
                {
                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //sum
                    A11 = A + r * col + kk;
                    B11 = B + kk * col2 + cc_tiling_size - mulLen;
                    B21 = B11 + col2;
                    B31 = B21 + col2;
                    B41 = B31 + col2;
                    B51 = B41 + col2;
                    B61 = B51 + col2;
                    B71 = B61 + col2;
                    B81 = B71 + col2;
                    C1 = C + r * col2 + cc_tiling_size - mulLen;

                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
                    for (k = kk; k < max_kk_tiling_size; k += 8)
                    {
                        DEF_VLOAD_V(NDS_VEC_V16, B11);
                        DEF_VLOAD_V(NDS_VEC_V18, B21);
                        DEF_VLOAD_V(NDS_VEC_V20, B31);
                        DEF_VLOAD_V(NDS_VEC_V22, B41);
                        DEF_VLOAD_V(NDS_VEC_V24, B51);
                        DEF_VLOAD_V(NDS_VEC_V26, B61);
                        DEF_VLOAD_V(NDS_VEC_V28, B71);
                        DEF_VLOAD_V(NDS_VEC_V30, B81);
                        MM_TYPE_A tmpa11 = *A11++;
                        MM_TYPE_A tmpa12 = *A11++;
                        MM_TYPE_A tmpa13 = *A11++;
                        MM_TYPE_A tmpa14 = *A11++;
                        MM_TYPE_A tmpa15 = *A11++;
                        MM_TYPE_A tmpa16 = *A11++;
                        MM_TYPE_A tmpa17 = *A11++;
                        MM_TYPE_A tmpa18 = *A11++;
                        DEF_VMACC_V(NDS_VEC_V0, tmpa11, NDS_VEC_V16);
                        DEF_VMACC_V(NDS_VEC_V0, tmpa12, NDS_VEC_V18);
                        DEF_VMACC_V(NDS_VEC_V0, tmpa13, NDS_VEC_V20);
                        DEF_VMACC_V(NDS_VEC_V0, tmpa14, NDS_VEC_V22);
                        DEF_VMACC_V(NDS_VEC_V0, tmpa15, NDS_VEC_V24);
                        DEF_VMACC_V(NDS_VEC_V0, tmpa16, NDS_VEC_V26);
                        DEF_VMACC_V(NDS_VEC_V0, tmpa17, NDS_VEC_V28);
                        DEF_VMACC_V(NDS_VEC_V0, tmpa18, NDS_VEC_V30);

                        B11 += 8 * col2;
                        B21 += 8 * col2;
                        B31 += 8 * col2;
                        B41 += 8 * col2;
                        B51 += 8 * col2;
                        B61 += 8 * col2;
                        B71 += 8 * col2;
                        B81 += 8 * col2;
                    }
                    for (; k < kk_tiling_size; k++)
                    {
                        DEF_VLOAD_V(NDS_VEC_V20, B11);
