                        DEF_VMACC_V(NDS_VEC_V0, tmpa11, NDS_VEC_V20);
                        B11 += col2;
                    }
                    NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
                    DEF_VLOADVQ_V(NDS_VEC_V16, C1);
                    NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V16);
