{
    long curRow, curCol, vl;
    long col_2 = col >> 1;
    long res_col = col & 1;
    long row_2 = row >> 1;
    long max_row = row_2 << 1;

    for (curRow = 0; curRow < max_row; curRow += 2)
    {
        const MM_TYPE_VQ* C1 = dst + col2 * curRow;
        const MM_TYPE_VQ* C2 = C1 + col2;

        long mulLen = col2;
        while (mulLen > 0)
        {
            NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPEVQ_SEW, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0); //C
            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0); //C
            const MM_TYPE_A* A1 = src1 + curRow * col;
            const MM_TYPE_A* A2 = A1 + col;
            const MM_TYPE_B* B0 = src2 + col2 - mulLen;
            const MM_TYPE_B* B1 = B0 + col2;

            NDS_VEC_VSETVLI(vl, mulLen, DEF_VTYPE_SEW, NDS_VEC_VTYPE_LMUL_M2);
            for (curCol = 0; curCol < col_2; curCol++)
            {
                DEF_VLOAD_V(NDS_VEC_V16, B0);
                DEF_VLOAD_V(NDS_VEC_V18, B1);
                MM_TYPE_A tmpa00 = *A1++;
                MM_TYPE_A tmpa10 = *A2++;
                DEF_VMACC_V(NDS_VEC_V0, tmpa00, NDS_VEC_V16);
                DEF_VMACC_V(NDS_VEC_V8, tmpa10, NDS_VEC_V16);

                MM_TYPE_A tmpa01 = *A1++;
                MM_TYPE_A tmpa11 = *A2++;
