                DEF_VMACC_V(NDS_VEC_V8, tmpa11, NDS_VEC_V18);

                B0 += 2 * col2;
                B1 += 2 * col2;
            }
            for (curCol = 0; curCol < res_col; curCol++)
            {
                DEF_VLOAD_V(NDS_VEC_V16, B0);
                MM_TYPE_A tmpa00 = *A1++;
                MM_TYPE_A tmpa10 = *A2++;
                DEF_VMACC_V(NDS_VEC_V0, tmpa00, NDS_VEC_V16);
                DEF_VMACC_V(NDS_VEC_V8, tmpa10, NDS_VEC_V16);
                B0 += col2;
