                                                             src2,
                                                             dst_i32,
                                                             out,
                                                             out_scale,
                                                             out_shift,
                                                             col_counter,
                                                             in_tensor_ch * ker_dim_x * ker_dim_y,
                                                             out_tensor_ch,
                                                             out_offset,
                                                             act_min,
                                                             act_max,
                                                             contri_buf,
                                                             tiling_size);

                /* counter reset */
                col_counter = 0;
