int32_t riscv_nn_conv_HWC_s8_s8_s8_asym_bias_any(const int8_t * in_tensor,
                                                 const uint16_t in_tensor_dim_x,
                                                 const uint16_t in_tensor_dim_y,
                                                 const uint16_t in_tensor_ch,
                                                 const uint16_t in_tensor_batch,
                                                 const int8_t * ker_weight,
                                                 const uint16_t out_tensor_ch,
                                                 const uint16_t ker_dim_x,
                                                 const uint16_t ker_dim_y,
                                                 const uint16_t pad_x,
                                                 const uint16_t pad_y,
                                                 const uint16_t stride_x,
                                                 const uint16_t stride_y,
                                                 const int32_t * bias,
                                                 int8_t * out_tensor,
                                                 const int32_t * out_shift,
                                                 const int32_t * out_scale,
                                                 const int32_t out_offset,    //value is in the range of [-128, 127]
                                                 const int32_t in_offset,     //value is in the range of [-127, 128]
                                                 const int32_t act_min,
                                                 const int32_t act_max,
                                                 const uint16_t out_tensor_dim_x,
                                                 const uint16_t out_tensor_dim_y,
                                                 int16_t * in_tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64) && defined(ENA_VEC_INTRINSIC)
    int i_batch;
    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        int32_t i_out_y, i_out_x, i_ker_y, i_ker_x;

        /* Generate two columns from the input tensor a GEMM computation */
        int8_t *two_column_buf = (int8_t *)in_tmp_buf;
        int8_t *out = out_tensor;
        long vl;

        /* This part implements the im2col function */
        for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
        {
            for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
            {
                for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
                {
                    for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
                    {
