                                                          out);

                    /* counter reset */
                    two_column_buf2 = (int8_t *)two_column_buf;
                }
            }
        }

        /* left-over because odd number of out_tensor pixels */
        if (two_column_buf2 != (int8_t *)two_column_buf)
        {
            const int8_t *pWt = ker_weight;

            for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
            {
                const int8_t *pIn = (int8_t *)two_column_buf;
                long acc = 0;
                long rhs_cols2 = rhs_cols;

                while (rhs_cols2 >= SIMD_NUM_Q7)
                {
                    suni_t in_val = simd_load_8((s8_t*)pIn, 0);
                    suni_t wt_val = simd_load_8((s8_t*)pWt, 0);
                    acc = NDS_DSP_SMAQA(acc, in_val.l0, wt_val.l0);
                    pIn += SIMD_NUM_Q7;
                    pWt += SIMD_NUM_Q7;
                    rhs_cols2 -= SIMD_NUM_Q7;
                }

                // rest loop
                int32_t acc_s32 = 0;
                while (rhs_cols2 > 0)
                {
                    acc_s32 += *pIn * *pWt;
                    pIn++;
                    pWt++;
                    rhs_cols2--;
                }

                // sum up the high and low part result
                acc = PADD_S32(acc);
                // final accumulator
                acc += acc_s32;
                // add contribution back
                acc += contri_buf[cur_out_ch];

                acc = nn_requantize(acc, out_scale[cur_out_ch], out_shift[cur_out_ch]);
                acc += out_offset;
                acc = MAX(acc, act_min);
                acc = MIN(acc, act_max);
                *out++ = (int8_t)acc;
            }
        }

        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
    }
#elif defined(ENA_DSP_ISA_V5)
    const uint32_t rhs_cols = ker_dim_y * ker_dim_x * in_tensor_ch;

    //--- calculate the buffer address ---
    const long align_byte = sizeof(long);
    // buffer-1
    int8_t *two_column_buf = (int8_t*)in_tmp_buf;
    two_column_buf = (int8_t*)nn_align((unsigned long)two_column_buf, align_byte);  // align the starting addresss
    // buffer-2
    long two_column_buf_size = 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(*in_tensor);
    int32_t *contri_buf = (int32_t*)(two_column_buf + two_column_buf_size);
    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);         // align the starting addresss

    // calculate the weight contribution
    const int8_t *pWt = ker_weight;
    const long cst_one = 0x01010101;

    for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
    {
        long sum = 0;
        long rhs_cols2 = rhs_cols;

        while (rhs_cols2 >= SIMD_NUM_Q7)
        {
            suni_t wt_s8 = simd_load_8((s8_t*)pWt, 0);
            sum = NDS_DSP_SMAQA(sum, wt_s8.l0, cst_one);
            rhs_cols2 -= SIMD_NUM_Q7;
            pWt += SIMD_NUM_Q7;
        }

        // rest loop
        while (rhs_cols2 > 0)
        {
            sum += *pWt;
            rhs_cols2--;
            pWt++;
        }

        sum *= in_offset;

        if (bias != NULL)
        {
            sum += bias[cur_out_ch];
        }
        contri_buf[cur_out_ch] = sum;
    }

    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        int8_t *two_column_buf2 = (int8_t *)two_column_buf;
        int8_t *out = out_tensor;

        /* This part implements the im2col function */
        for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
        {
            for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
            {
                for (long cur_ker_y = cur_out_y * stride_y - pad_y; cur_ker_y < cur_out_y * stride_y - pad_y + ker_dim_y; cur_ker_y++)
                {
                    for (long cur_ker_x = cur_out_x * stride_x - pad_x; cur_ker_x < cur_out_x * stride_x - pad_x + ker_dim_x; cur_ker_x++)
                    {
                        if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
                        {
                            nn_set_val_s8(two_column_buf2, -in_offset, in_tensor_ch);
                        }
                        else
                        {
                            nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, two_column_buf2, in_tensor_ch);
                        }
                        two_column_buf2 += in_tensor_ch;
                    }
                }

                /* Computation is filed for every 2 columns */
                if (two_column_buf2 == (int8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim_y * ker_dim_x)
                {
                    out = nn_mat_mult_kernel_s8_offset_v2(ker_weight,
                                                          two_column_buf,
                                                          out_tensor_ch,
                                                          out_shift,
                                                          out_scale,
                                                          in_offset,
                                                          out_offset,
                                                          act_min,
                                                          act_max,
                                                          rhs_cols,
                                                          contri_buf,
                                                          out);

                    /* counter reset */
                    two_column_buf2 = (int8_t *)two_column_buf;
                }
            }
        }

        /* left-over because odd number of out_tensor pixels */
        if (two_column_buf2 != (int8_t *)two_column_buf)
        {
            const int8_t *pWt = ker_weight;

            for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
            {
                const int8_t *pIn = (int8_t *)two_column_buf;
                long acc = 0;
                long rhs_cols2 = rhs_cols;

                while (rhs_cols2 >= SIMD_NUM_Q7)
                {
                    suni_t in_val = simd_load_8((s8_t*)pIn, 0);
                    suni_t wt_val = simd_load_8((s8_t*)pWt, 0);
                    acc = NDS_DSP_SMAQA(acc, in_val.l0, wt_val.l0);
                    pIn += SIMD_NUM_Q7;
                    pWt += SIMD_NUM_Q7;
                    rhs_cols2 -= SIMD_NUM_Q7;
                }

                // rest loop
                while (rhs_cols2 > 0)
                {
                    acc += *pIn * *pWt;
                    pIn++;
                    pWt++;
                    rhs_cols2--;
                }

                // add contribution back
                acc += contri_buf[cur_out_ch];

                acc = nn_requantize(acc, out_scale[cur_out_ch], out_shift[cur_out_ch]);
                acc += out_offset;
                acc = MAX(acc, act_min);
                acc = MIN(acc, act_max);
                *out++ = (int8_t)acc;
            }
        }

        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
    }
#else
    int i_batch;
    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        (void)in_tmp_buf;
        int32_t i_out_ch, i_out_y, i_out_x, i_input_ch, i_ker_y, i_ker_x;
        int32_t conv_out;

        for (i_out_ch = 0; i_out_ch < out_tensor_ch; i_out_ch++)
        {
            for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
            {
                for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
                {
                    conv_out = 0;
                    if (bias)
                    {
                        conv_out = bias[i_out_ch];
                    }

                    const int32_t base_idx_y = stride_y * i_out_y - pad_y;
                    const int32_t base_idx_x = stride_x * i_out_x - pad_x;

                    const int32_t ker_y_start = MAX(0, -base_idx_y);
                    const int32_t ker_x_start = MAX(0, -base_idx_x);

                    const int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
                    const int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);

                    for (i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
                    {
                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
                        {
                            const int32_t in_row = base_idx_y + i_ker_y;
                            const int32_t in_col = base_idx_x + i_ker_x;
                            for (i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
                            {
                                conv_out +=
                                    (in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + i_input_ch] + in_offset) *
                                    ker_weight[i_out_ch * in_tensor_ch * ker_dim_y * ker_dim_x +
                                           (i_ker_y * ker_dim_x + i_ker_x) * in_tensor_ch + i_input_ch];
                            }
                        }
                    }
                    conv_out = nn_requantize(conv_out, out_scale[i_out_ch], out_shift[i_out_ch]);
                    conv_out += out_offset;
                    conv_out = MAX(conv_out, act_min);
                    conv_out = MIN(conv_out, act_max);
                    out_tensor[i_out_ch + (i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch] = (int8_t)conv_out;
                }
            }
        }
        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
    }
#endif  //ENA_EMPTY_FUN

    /* Return to application */
    return 0;
}

int32_t riscv_nn_conv_HWC_s8_s8_s8_asym_bias_any_get_buffer_size(const uint16_t in_tensor_dim_x,
                                                                 const uint16_t in_tensor_dim_y,
                                                                 const uint16_t in_tensor_ch,
                                                                 const uint16_t out_tensor_ch,
                                                                 const uint16_t ker_dim_x,
                                                                 const uint16_t ker_dim_y,
                                                                 const uint16_t pad_x,
                                                                 const uint16_t pad_y,
                                                                 const uint16_t stride_x,
                                                                 const uint16_t stride_y,
                                                                 const uint16_t out_tensor_dim_x,
                                                                 const uint16_t out_tensor_dim_y)
{
    (void) in_tensor_dim_x;
    (void) in_tensor_dim_y;
    (void) pad_x;
    (void) pad_y;
    (void) stride_x;
    (void) stride_y;
    (void) out_tensor_dim_x;
    (void) out_tensor_dim_y;
    int32_t buf_size = 0;
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING)
    uint32_t buf_A = 0, buf_B = 0, buf_C = 0, buf_contri = 0;
    const long align_byte = 64;
    uint32_t tiling_size = 256;
#ifdef DCACHE_SIZE
    int i;
    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / (6 * sizeof(int8_t)));
    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
    {
        if (tiling_size_arr[i] > max_tile_size_in_cache)
        {
            tiling_size = tiling_size_arr[i - 1];
            break;
        }
    }
#endif
    buf_A = tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t); //tiling version
    buf_A += align_byte - 1;
    buf_B = out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t); //converted src2
    buf_B += align_byte - 1;
    buf_C = tiling_size * out_tensor_ch * sizeof(int32_t); //temp buffer for q31 tiling accumulator
    buf_C += align_byte - 1;
    buf_contri = out_tensor_ch * sizeof(int32_t); //contribution
    buf_contri += align_byte - 1;
    buf_size = buf_A + buf_B + buf_C + buf_contri;
#elif (defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)) || (defined(ENA_DSP_ISA))
    const long align_byte = sizeof(long);

    // two col buffer
    buf_size = 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for extra contribution
    buf_size += out_tensor_ch * sizeof(int32_t);
    buf_size += align_byte - 1;     //extra size for aligning
#else
    (void)in_tensor_ch;
    (void)out_tensor_ch;
    (void)ker_dim_x;
    (void)ker_dim_y;
#endif
    return buf_size;
}
